// Update lessons 161-200 with detailed descriptions
// Run: npx tsx scripts/update-lessons-161-200.ts

import { config } from 'dotenv';
config();

import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

const detailedLessons: { order: number; ruDescription: string; uzDescription: string; ruFunctionality: string; uzFunctionality: string }[] = [
  // === ФИНАНСЫ: ЗАРПЛАТА (161-163) ===
  { order: 161, ruDescription: 'Раздел "Зарплата" предназначен для автоматизации расчёта и выплаты заработной платы сотрудникам организации. Это важный модуль для управления персоналом и учёта трудовых затрат.\n\nВ разделе отображается список сотрудников с информацией о начисленной и выплаченной зарплате. Можно настроить различные системы оплаты: оклад, почасовая, сдельная, а также премии и надбавки.\n\nАвтоматический расчёт зарплаты учитывает отработанное время, больничные, отпуска и другие факторы. Это значительно упрощает работу бухгалтерии и исключает ошибки в расчётах.', uzDescription: '"Ish haqi" bo\'limi tashkilot xodimlarining ish haqini hisoblash va to\'lashni avtomatlashtirish uchun mo\'ljallangan. Bu personalni boshqarish va mehnat xarajatlarini hisobga olishning muhim moduli.\n\nBo\'limda hisoblangan va to\'langan ish haqi haqida ma\'lumot bilan xodimlar ro\'yxati ko\'rsatiladi. Turli to\'lov tizimlarini sozlash mumkin: oylik, soatlik, buyurtma, shuningdek mukofotlar va qo\'shimchalar.\n\nIsh haqini avtomatik hisoblash ishlangan vaqtni, kasallik varaqalarini, ta\'tillarni va boshqa omillarni hisobga oladi. Bu buxgalteriya ishini ancha soddalashtiradi va hisob-kitoblarda xatolarni istisno qiladi.', ruFunctionality: 'Открывает модуль расчёта зарплат с полным функционалом для управления вознаграждениями сотрудников. В модуле можно настроить базовые ставки, премии, налоги и отчисления.\n\nСистема автоматически рассчитывает зарплату на основе табеля учёта рабочего времени и настроенных правил. Поддерживаются различные периоды расчёта: еженедельно, раз в две недели, ежемесячно.\n\nИнтеграция с финансовым модулем позволяет автоматически формировать платежи и учитывать их в расходах организации.', uzFunctionality: 'Xodimlarning mukofotlarini boshqarish uchun to\'liq funksional bilan ish haqini hisoblash modulini ochadi. Modulda bazaviy stavkalar, mukofotlar, soliqlar va ajratmalarni sozlash mumkin.\n\nTizim ish vaqtini hisobga olish jadvali va sozlangan qoidalar asosida ish haqini avtomatik hisoblaydi. Turli hisoblash davrlari qo\'llab-quvvatlanadi: haftalik, ikki haftalik, oylik.\n\nMoliyaviy modul bilan integratsiya to\'lovlarni avtomatik shakllantirish va ularni tashkilot xarajatlarida hisobga olish imkonini beradi.' },

  { order: 162, ruDescription: 'Кнопка начисления зарплаты инициирует расчёт заработной платы за выбранный период. Это ключевой этап в процессе расчёта с сотрудниками за их труд.\n\nПри начислении система анализирует данные табеля учёта рабочего времени, применяет настроенные правила расчёта и формирует сумму к выплате для каждого сотрудника.\n\nРезультаты начисления можно просмотреть и скорректировать перед утверждением. Это позволяет учесть дополнительные премии или удержания, не предусмотренные автоматическим расчётом.', uzDescription: 'Ish haqini hisoblash tugmasi tanlangan davr uchun ish haqini hisoblashni boshlaydi. Bu xodimlar bilan mehnatlari uchun hisob-kitob jarayonida asosiy bosqich.\n\nHisoblashda tizim ish vaqtini hisobga olish jadvali ma\'lumotlarini tahlil qiladi, sozlangan hisoblash qoidalarini qo\'llaydi va har bir xodim uchun to\'lanadigan summani shakllantiradi.\n\nHisoblash natijalarini tasdiqlashdan oldin ko\'rish va tuzatish mumkin. Bu avtomatik hisoblashda nazarda tutilmagan qo\'shimcha mukofotlar yoki ushlab qolishlarni hisobga olish imkonini beradi.', ruFunctionality: 'Запускает процесс автоматического расчёта заработной платы для всех сотрудников или выбранной группы. Расчёт выполняется на основе данных об отработанном времени и настроенных ставках.\n\nСистема учитывает налоговые вычеты, социальные отчисления и другие удержания согласно законодательству. Результаты расчёта сохраняются и доступны для просмотра и редактирования.\n\nПосле начисления формируется ведомость с детализацией по каждому сотруднику: оклад, премии, удержания, сумма к выплате.', uzFunctionality: 'Barcha xodimlar yoki tanlangan guruh uchun ish haqini avtomatik hisoblash jarayonini boshlaydi. Hisoblash ishlangan vaqt ma\'lumotlari va sozlangan stavkalar asosida amalga oshiriladi.\n\nTizim qonunchilikka muvofiq soliq chegirmalari, ijtimoiy ajratmalar va boshqa ushlab qolishlarni hisobga oladi. Hisoblash natijalari saqlanadi va ko\'rish hamda tahrirlash uchun mavjud.\n\nHisoblangandan so\'ng har bir xodim bo\'yicha batafsil ma\'lumot bilan vedomost shakllantiriladi: oylik, mukofotlar, ushlab qolishlar, to\'lanadigan summa.' },

  { order: 163, ruDescription: 'Кнопка выплаты зарплаты фиксирует факт передачи денежных средств сотрудникам. Это финальный этап расчётного цикла по оплате труда.\n\nПри выплате система создаёт расходный документ, который уменьшает остаток денежных средств на счёте организации. Выплата может быть произведена наличными или безналичным переводом.\n\nИстория выплат сохраняется и доступна для анализа и формирования отчётности. Это важно для налогового учёта и решения спорных вопросов с сотрудниками.', uzDescription: 'Ish haqini to\'lash tugmasi pul mablag\'larining xodimlarga uzatilish faktini qayd etadi. Bu mehnat haqini to\'lash bo\'yicha hisob-kitob tsiklining yakuniy bosqichi.\n\nTo\'lovda tizim xarajat hujjatini yaratadi, bu tashkilot hisobidagi pul mablag\'lari qoldig\'ini kamaytiradi. To\'lov naqd pul yoki hisob-kitob o\'tkazmasi bilan amalga oshirilishi mumkin.\n\nTo\'lovlar tarixi saqlanadi va tahlil qilish hamda hisobotlarni shakllantirish uchun mavjud. Bu soliq hisobi va xodimlar bilan bahsli masalalarni hal qilish uchun muhim.', ruFunctionality: 'Создаёт платёжный документ на выплату начисленной зарплаты сотрудникам. Документ проходит через стандартный процесс согласования и проведения финансовых операций.\n\nПри выборе безналичной выплаты система формирует реестр для банка с реквизитами сотрудников. При наличной выплате формируется расходный кассовый ордер.\n\nПосле проведения выплаты статус начисления меняется на "Выплачено", а сумма отражается в финансовых отчётах как расход на оплату труда.', uzFunctionality: 'Xodimlarga hisoblangan ish haqini to\'lash uchun to\'lov hujjatini yaratadi. Hujjat moliyaviy operatsiyalarni tasdiqlash va o\'tkazishning standart jarayonidan o\'tadi.\n\nHisob-kitobsiz to\'lov tanlanganda tizim xodimlarning rekvizitlari bilan bank uchun reestr shakllantiradi. Naqd to\'lovda chiqim kassa ordeni shakllantiriladi.\n\nTo\'lov o\'tkazilgandan so\'ng hisoblash holati "To\'langan" ga o\'zgaradi va summa moliyaviy hisobotlarda mehnat haqi xarajati sifatida aks etadi.' },

  // === ОТЧЁТЫ: ПРОДАЖИ (164-167) ===
  { order: 164, ruDescription: 'Раздел "Отчёт о продаже" предоставляет детальную аналитику по всем продажам организации за выбранный период. Это ключевой инструмент для анализа коммерческой деятельности и принятия управленческих решений.\n\nОтчёт содержит информацию о выручке, количестве продаж, среднем чеке и других показателях эффективности. Данные можно группировать по точкам продаж, категориям товаров, продавцам и другим параметрам.\n\nВизуализация в виде графиков и диаграмм наглядно показывает динамику продаж и позволяет выявлять тренды. Это помогает планировать закупки и оптимизировать ассортимент.', uzDescription: '"Sotuv hisoboti" bo\'limi tanlangan davr mobaynida tashkilotning barcha sotuvlari bo\'yicha batafsil tahlilni taqdim etadi. Bu tijorat faoliyatini tahlil qilish va boshqaruv qarorlarini qabul qilish uchun asosiy vosita.\n\nHisobot tushum, sotuvlar soni, o\'rtacha chek va boshqa samaradorlik ko\'rsatkichlari haqida ma\'lumotni o\'z ichiga oladi. Ma\'lumotlarni savdo nuqtalari, tovar kategoriyalari, sotuvchilar va boshqa parametrlar bo\'yicha guruhlash mumkin.\n\nGrafiklar va diagrammalar ko\'rinishidagi vizualizatsiya sotuvlar dinamikasini aniq ko\'rsatadi va tendensiyalarni aniqlashga yordam beradi. Bu xaridlarni rejalashtirish va assortimentni optimallashtirishga yordam beradi.', ruFunctionality: 'Открывает детальный отчёт по продажам с возможностью настройки параметров отображения. Можно выбрать период, точки продаж, категории товаров и другие фильтры.\n\nОтчёт автоматически рассчитывает ключевые показатели: выручку, прибыль, средний чек, количество позиций в чеке. Данные обновляются в реальном времени при появлении новых продаж.\n\nИнтерактивные графики позволяют детализировать данные и анализировать причины роста или падения продаж. Отчёт можно выгрузить в Excel для дальнейшей работы.', uzFunctionality: 'Ko\'rsatish parametrlarini sozlash imkoniyati bilan sotuvlar bo\'yicha batafsil hisobotni ochadi. Davrni, savdo nuqtalarini, tovar kategoriyalarini va boshqa filtrlarni tanlash mumkin.\n\nHisobot asosiy ko\'rsatkichlarni avtomatik hisoblaydi: tushum, foyda, o\'rtacha chek, chekdagi pozitsiyalar soni. Ma\'lumotlar yangi sotuvlar paydo bo\'lganda real vaqtda yangilanadi.\n\nInteraktiv grafiklar ma\'lumotlarni batafsil ko\'rsatish va sotuvlarning o\'sish yoki tushish sabablarini tahlil qilish imkonini beradi. Hisobotni keyingi ish uchun Excelga yuklab olish mumkin.' },

  { order: 165, ruDescription: 'Фильтр отчёта по дате позволяет ограничить период анализируемых данных. Это базовый инструмент для работы с любыми отчётами системы.\n\nМожно выбрать стандартный период: сегодня, вчера, текущая неделя, месяц, квартал, год. Также доступен произвольный период с указанием конкретных дат начала и окончания.\n\nПравильный выбор периода позволяет сравнивать показатели за разные временные отрезки и оценивать динамику развития бизнеса. Это важно для сезонного анализа и планирования.', uzDescription: 'Hisobotni sana bo\'yicha filtr tahlil qilinadigan ma\'lumotlar davrini cheklash imkonini beradi. Bu tizimning istalgan hisobotlari bilan ishlash uchun asosiy vosita.\n\nStandart davrni tanlash mumkin: bugun, kecha, joriy hafta, oy, chorak, yil. Shuningdek boshlanish va tugash sanalarini ko\'rsatib, ixtiyoriy davr ham mavjud.\n\nDavrga to\'g\'ri tanlash turli vaqt oralig\'idagi ko\'rsatkichlarni solishtirish va biznes rivojlanish dinamikasini baholash imkonini beradi. Bu mavsumiy tahlil va rejalashtirish uchun muhim.', ruFunctionality: 'Открывает календарь для выбора периода отчёта. При выборе периода система автоматически обновляет данные в отчёте с учётом нового временного интервала.\n\nФильтр запоминает последний выбранный период и применяет его к другим отчётам. Это ускоряет работу при анализе нескольких отчётов за один период.\n\nПри выборе периода отображается подсказка с количеством включённых дней и граничными датами для контроля корректности выбора.', uzFunctionality: 'Hisobot davrini tanlash uchun kalendarni ochadi. Davr tanlanganda tizim hisobotdagi ma\'lumotlarni yangi vaqt oralig\'ini hisobga olgan holda avtomatik yangilaydi.\n\nFiltr oxirgi tanlangan davrni eslab qoladi va boshqa hisobotlarga qo\'llaydi. Bu bir davr uchun bir nechta hisobotlarni tahlil qilishda ishni tezlashtiradi.\n\nDavr tanlanganda kunlar soni va chegara sanalari bilan maslahat ko\'rsatiladi, bu tanlov to\'g\'riligini nazorat qilish uchun.' },

  { order: 166, ruDescription: 'Функция экспорта отчёта позволяет сохранить данные в файл для работы во внешних программах. Это востребованная возможность для формирования презентаций и передачи данных руководству.\n\nЭкспорт доступен в форматах Excel и PDF. В формате Excel сохраняется структура данных с возможностью редактирования, а PDF подходит для печати и рассылки.\n\nПри экспорте сохраняются все применённые фильтры и группировки. Это гарантирует, что выгруженные данные соответствуют текущему виду отчёта на экране.', uzDescription: 'Hisobotni eksport qilish funksiyasi ma\'lumotlarni tashqi dasturlarda ishlash uchun faylga saqlash imkonini beradi. Bu taqdimotlarni shakllantirish va ma\'lumotlarni rahbariyatga uzatish uchun talab qilinadigan imkoniyat.\n\nEksport Excel va PDF formatlarida mavjud. Excel formatida ma\'lumotlar tuzilishi tahrirlash imkoniyati bilan saqlanadi, PDF esa chop etish va tarqatish uchun mos.\n\nEksportda qo\'llangan barcha filtrlar va guruhlar saqlanadi. Bu yuklangan ma\'lumotlar ekrandagi hisobotning joriy ko\'rinishiga mos kelishini kafolatlaydi.', ruFunctionality: 'Формирует файл с данными отчёта в выбранном формате. Процесс экспорта занимает несколько секунд в зависимости от объёма данных.\n\nПри экспорте в Excel система создаёт файл с форматированием: заголовки, условное форматирование, итоговые строки. Это позволяет сразу работать с данными без дополнительной настройки.\n\nЭкспортированный файл автоматически скачивается на компьютер пользователя. Можно настроить отправку файла на электронную почту по расписанию.', uzFunctionality: 'Tanlangan formatda hisobot ma\'lumotlari bilan faylni shakllantiradi. Eksport jarayoni ma\'lumotlar hajmiga qarab bir necha soniya davom etadi.\n\nExcelga eksport qilishda tizim formatlash bilan fayl yaratadi: sarlavhalar, shartli formatlash, yakuniy qatorlar. Bu ma\'lumotlar bilan darhol qo\'shimcha sozlamalarsiz ishlash imkonini beradi.\n\nEksport qilingan fayl avtomatik foydalanuvchi kompyuteriga yuklab olinadi. Faylni jadval bo\'yicha elektron pochtaga yuborishni sozlash mumkin.' },

  { order: 167, ruDescription: 'Раздел "Топ продаж" показывает рейтинг наиболее продаваемых товаров за выбранный период. Это важный инструмент для анализа ассортимента и оптимизации запасов.\n\nРейтинг формируется на основе количества проданных единиц или суммы выручки. Можно переключаться между этими критериями для получения разных视角 анализа.\n\nИнформация о топ-продажах помогает принимать решения о закупках, продвижении товаров и формировании ассортимента. Хиты продаж должны быть всегда в наличии и на видном месте.', uzDescription: '"Sotuvlar reytingi" bo\'limi tanlangan davr mobaynida eng ko\'p sotilgan tovarlar reytingini ko\'rsatadi. Bu assortimentni tahlil qilish va zaxiralarni optimallashtirish uchun muhim vosita.\n\nReyting sotilgan birliklar soni yoki tushum summasi asosida shakllantiriladi. Turli tahlil nuqtai nazarlarini olish uchun bu mezonlar o\'rtasida o\'tish mumkin.\n\nTop-sotuvlar haqidagi ma\'lumotlar xaridlar, tovarlarni rag\'batlantirish va assortimentni shakllantirish bo\'yicha qarorlar qabul qilishga yordam beradi. Sotuv hitlari har doim mavjud va ko\'zga tashlanadigan joyda bo\'lishi kerak.', ruFunctionality: 'Отображает рейтинг товаров по объёму продаж с возможностью детализации по различным параметрам. Можно анализировать топ по категориям, брендам, точкам продаж.\n\nРейтинг обновляется в реальном времени при появлении новых продаж. Товары сбыстро растущей динамикой отмечаются специальным индикатором для внимания менеджера.\n\nИз рейтинга можно перейти в карточку товара для анализа причин популярности или наоборот — отсутствия в топе.', uzFunctionality: 'Turli parametrlar bo\'yicha batafsil ko\'rish imkoniyati bilan sotuvlar hajmi bo\'yicha tovarlar reytingini ko\'rsatadi. Kategoriyalar, brendlar, savdo nuqtalari bo\'yicha topni tahlil qilish mumkin.\n\nReyting yangi sotuvlar paydo bo\'lganda real vaqtda yangilanadi. Tez o\'sayotgan dinamikali tovarlar menejer e\'tibori uchun maxsus indikator bilan belgilanadi.\n\nReytingdan tovar kartochkasiga o\'tish, ommaboplik sabablarini yoki aksincha — topda yo\'qligini tahlil qilish mumkin.' },

  // === ОТЧЁТЫ: ФИНАНСЫ (168-172) ===
  { order: 168, ruDescription: 'Отчёт P&L (Profit and Loss) — это отчёт о прибылях и убытках организации за период. Это ключевой финансовый документ для оценки эффективности бизнеса.\n\nОтчёт показывает структуру доходов и расходов, валовую прибыль, операционные расходы и чистую прибыль. Все показатели рассчитываются автоматически на основе данных учёта.\n\nАнализ P&L позволяет выявить проблемные зоны в финансах и принять меры по повышению рентабельности. Сравнение отчётов за разные периоды показывает динамику развития.', uzDescription: 'P&L (Profit and Loss) hisoboti — bu davr mobaynida tashkilotning foyda va zarari haqidagi hisobot. Bu biznes samaradorligini baholash uchun asosiy moliyaviy hujjat.\n\nHisobot daromadlar va xarajatlar tuzilmasini, yalpi foyda, operatsion xarajatlar va sof foydani ko\'rsatadi. Barcha ko\'rsatkichlar hisob ma\'lumotlari asosida avtomatik hisoblanadi.\n\nP&L tahlili moliyaviy muammoli joylarni aniqlash va rentabellikni oshirish choralarini ko\'rish imkonini beradi. Turli davrlardagi hisobotlarni solishtirish rivojlanish dinamikasini ko\'rsatadi.', ruFunctionality: 'Формирует финансовый отчёт о прибылях и убытках с детализацией по статьям. Отчёт автоматически рассчитывает все показатели на основе проведённых финансовых операций.\n\nМожно настроить уровень детализации: от общего P&L до детализации по подразделениям или проектам. Это позволяет анализировать вклад каждого направления в общий результат.\n\nОтчёт можно сравнивать с планом или аналогичным периодом прошлого года для оценки выполнения целей.', uzFunctionality: 'Maqolalar bo\'yicha batafsil ko\'rish bilan foyda va zarar haqidagi moliyaviy hisobotni shakllantiradi. Hisobot o\'tkazilgan moliyaviy operatsiyalar asosida barcha ko\'rsatkichlarni avtomatik hisoblaydi.\n\nBatafsil darajasini sozlash mumkin: umumiy P&L dan bo\'linmalar yoki loyihalar bo\'yicha batafsil ko\'rishgacha. Bu har bir yo\'nalishning umumiy natijaga hissasini tahlil qilish imkonini beradi.\n\nHisobotni rejalar yoki o\'tgan yilning shu davri bilan solishtirish, maqsadlarni bajarishni baholash uchun mumkin.' },

  { order: 169, ruDescription: 'Отчёт "Салдо" показывает остатки и балансы по всем счетам и складам организации. Это сводный документ для контроля состояния активов и обязательств.\n\nВ отчёте отображаются начальные и конечные остатки, обороты за период по каждому счёту. Это позволяет отследить движение средств и товаров.\n\nСалдо используется для подготовки бухгалтерской отчётности и финансового анализа. Сверка остатков помогает выявлять расхождения и ошибки в учёте.', uzDescription: '"Saldo" hisoboti tashkilotning barcha hisob va omborlaridagi qoldiqlar va balanslarni ko\'rsatadi. Bu aktivlar va majburiyatlar holatini nazorat qilish uchun yig\'ma hujjat.\n\nHisobotda boshlang\'ich va yakuniy qoldiqlar, davr mobaynida har bir hisob bo\'yicha aylanmalar ko\'rsatiladi. Bu mablag\'lar va tovarlar harakatini kuzatish imkonini beradi.\n\nSaldo buxgalteriya hisobotini tayyorlash va moliyaviy tahlil uchun ishlatiladi. Qoldiqlarni solishtirish hisobdagi farqlar va xatolarni aniqlashga yordam beradi.', ruFunctionality: 'Отображает сводную таблицу остатков по счетам учёта с начальными и конечными сальдо. Можно детализировать отчёт по конкретным счетам, складам или контрагентам.\n\nОтчёт автоматически рассчитывается на основе всех проведённых документов за период. Данные обновляются в реальном времени при изменениях в учёте.\n\nМожно сформировать оборотно-сальдовую ведомость для детального анализа движений по каждому счёту.', uzFunctionality: 'Boshlang\'ich va yakuniy saldolar bilan hisob hisoblaridagi qoldiqlar yig\'ma jadvalini ko\'rsatadi. Hisobotni aniq hisoblar, omborlar yoki kontragentlar bo\'yicha batafsil ko\'rish mumkin.\n\nHisobot davr mobaynida o\'tkazilgan barcha hujjatlar asosida avtomatik hisoblanadi. Ma\'lumotlar hisobda o\'zgarishlar bo\'lganda real vaqtda yangilanadi.\n\nHar bir hisob bo\'yicha harakatlarni batafsil tahlil qilish uchun aylanma-saldo vedomostini shakllantirish mumkin.' },

  { order: 170, ruDescription: 'Материальный отчёт показывает движение материалов и товаров за период. Это важный документ для контроля использования ресурсов и выявления потерь.\n\nОтчёт содержит информацию о начальных остатках, поступлении, расходе и конечных остатках по каждому виду материалов. Можно группировать данные по складам, категориям и поставщикам.\n\nАнализ материального отчёта помогает оптимизировать закупки, выявлять неэффективное использование материалов и контролировать сохранность ценностей.', uzDescription: 'Material hisoboti davr mobaynida materiallar va tovarlar harakatini ko\'rsatadi. Bu resurslardan foydalanishni nazorat qilish va yo\'qotishlarni aniqlash uchun muhim hujjat.\n\nHisobot har bir material turi bo\'yicha boshlang\'ich qoldiqlar, kelib tushish, sarflash va yakuniy qoldiqlar haqida ma\'lumotni o\'z ichiga oladi. Ma\'lumotlarni omborlar, kategoriyalar va yetkazib beruvchilar bo\'yicha guruhlash mumkin.\n\nMaterial hisobotini tahlil qilish xaridlarni optimallashtirish, materiallardan samarasiz foydalanishni aniqlash va qadriyatlarning saqlanishini nazorat qilishga yordam beradi.', ruFunctionality: 'Формирует отчёт о движении товарно-материальных ценностей с детализацией по позициям. Отчёт показывает, откуда и в каком количестве поступили материалы и куда они были израсходованы.\n\nМожно отфильтровать отчёт по конкретным складам, категориям товаров или периодам. Это позволяет анализировать движение конкретной группы материалов.\n\nОтчёт автоматически рассчитывает среднюю себестоимость и показывает стоимость остатков и движений.', uzFunctionality: 'Pozitsiyalar bo\'yicha batafsil ko\'rish bilan tovar-moddaviy qadriyatlar harakati haqida hisobot shakllantiradi. Hisobot materiallar qayerdan va qancha miqdorda kelganini va qayerga sarflaganligini ko\'rsatadi.\n\nHisobotni aniq omborlar, tovar kategoriyalari yoki davrlar bo\'yicha filtrlash mumkin. Bu aniq material guruhi harakatini tahlil qilish imkonini beradi.\n\nHisobot o\'rtacha tannarxni avtomatik hisoblaydi va qoldiqlar va harakatlar qiymatini ko\'rsatadi.' },

  { order: 171, ruDescription: 'Отчёт ABC — это метод классификации товаров по их значимости для бизнеса. Товары распределяются на три группы: A (наиболее ценные), B (промежуточные), C (наименее ценные).\n\nКатегория A обычно включает 20% товаров, которые дают 80% выручки — это ключевые позиции ассортимента. Категория B — товары со средней значимостью, категория C — товары с низким вкладом в выручку.\n\nРезультаты ABC-анализа используются для оптимизации запасов, управления ассортиментом и принятия решений о закупках. Внимание сосредотачивается на наиболее важных позициях.', uzDescription: 'ABC hisoboti — bu tovarlarning biznes uchun ahamiyatiga qarab tasniflash usuli. Tovarlar uchta guruhga bo\'linadi: A (eng qimmatli), B (o\'rtacha), C (eng kam qimmatli).\n\nA toifa odatda tushumning 80% beruvchi 20% tovarlarni o\'z ichiga oladi — bu assortimentning asosiy pozitsiyalari. B toifa — o\'rtacha ahamiyatga ega tovarlar, C toifa — tushumga oz hissa qo\'shuvchi tovarlar.\n\nABC tahlili natijalari zaxiralarni optimallashtirish, assortimentni boshqarish va xaridlar bo\'yicha qarorlar qabul qilish uchun ishlatiladi. E\'tibor eng muhim pozitsiyalarga qaratiladi.', ruFunctionality: 'Выполняет ABC-классификацию товаров на основе выручки или количества продаж. Результаты отображаются в виде таблицы и диаграммы с цветовым кодированием категорий.\n\nМожно настроить пороговые значения для категорий A, B, C в соответствии с особенностями бизнеса. Стандартные значения можно изменить для более точного анализа.\n\nОтчёт показывает процент товаров в каждой категории и их вклад в общий результат. Это помогает оценить сбалансированность ассортимента.', uzFunctionality: 'Tushum yoki sotuvlar soni asosida tovarlarning ABC-tasnifini amalga oshiradi. Natijalar jadval va toifalarni rangli kodlash bilan diagramma ko\'rinishida ko\'rsatiladi.\n\nA, B, C toifalari uchun chegara qiymatlarni biznes xususiyatlariga muvofiq sozlash mumkin. Standart qiymatlarni aniqroq tahlil uchun o\'zgartirish mumkin.\n\nHisobot har bir toifadagi tovarlar foizini va ularning umumiy natijaga hissasini ko\'rsatadi. Bu assortiment muvozanatini baholashga yordam beradi.' },

  { order: 172, ruDescription: 'Отчёт XYZ — это метод анализа стабильности спроса на товары. Товары классифицируются по коэффициенту вариации спроса: X (стабильный спрос), Y (сезонные колебания), Z (непредсказуемый спрос).\n\nКатегория X включает товары с минимальными колебаниями спроса — их легко планировать и поддерживать в наличии. Категория Y — товары с предсказуемыми сезонными изменениями. Категория Z — товары с хаотичным спросом, требующие особого подхода.\n\nРезультаты XYZ-анализа используются для оптимизации страховых запасов и управления закупками. Товары разных категорий требуют разных стратегий управления запасами.', uzDescription: 'XYZ hisoboti — bu tovarlarga bo\'lgan talab barqarorligini tahlil qilish usuli. Tovarlar talab o\'zgarish koeffitsienti bo\'yicha tasniflanadi: X (barqaror talab), Y (mavsumiy o\'zgarishlar), Z (bashorat qilib bo\'lmaydigan talab).\n\nX toifa talabning minimal o\'zgarishlari bo\'lgan tovarlarni o\'z ichiga oladi — ularni rejalashtirish va mavjud holda saqlash oson. Y toifa — oldindan aytib bo\'ladigan mavsumiy o\'zgarishlar bo\'lgan tovarlar. Z toifa — betartib talabli, maxsus yondashuvni talab qiluvchi tovarlar.\n\nXYZ tahlili natijalari sug\'urta zaxiralarini optimallashtirish va xaridlarni boshqarish uchun ishlatiladi. Turli toifadagi tovarlar zaxiralarni boshqarishning turli strategiyalarini talab qiladi.', ruFunctionality: 'Выполняет XYZ-классификацию товаров на основе коэффициента вариации продаж за период. Результаты отображаются с указанием коэффициента вариации и присвоенной категории.\n\nМожно выбрать период анализа и метод расчёта: по количеству или по сумме продаж. Рекомендуется анализировать период не менее 3 месяцев для достоверных результатов.\n\nОтчёт показывает распределение товаров по категориям и помогает определить оптимальную стратегию управления запасами для каждой группы.', uzFunctionality: 'Davr mobaynida sotuvlar o\'zgarish koeffitsienti asosida tovarlarning XYZ-tasnifini amalga oshiradi. Natijalar o\'zgarish koeffitsienti va berilgan toifani ko\'rsatgan holda ko\'rsatiladi.\n\nTahlil davrini va hisoblash usulini tanlash mumkin: miqdor yoki sotuv summasi bo\'yicha. Ishonchli natijalar uchun kamida 3 oylik davrni tahlil qilish tavsiya etiladi.\n\nHisobot tovarlarning toifalar bo\'yicha taqsimlanishini ko\'rsatadi va har bir guruh uchun zaxiralarni boshqarishning optimal strategiyasini aniqlashga yordam beradi.' },

  // === ОТЧЁТЫ: АНАЛИЗ (173-175) ===
  { order: 173, ruDescription: 'Отчёт ABC/XYZ — это комплексный анализ, объединяющий две классификации для более точного управления ассортиментом. Каждому товару присваивается двойная категория, например AX, BY, CZ.\n\nКатегория AX объединяет товары с высокой выручкой и стабильным спросом — это ключевые позиции, которые всегда должны быть в наличии. Категория CZ — товары с низким вкладом и непредсказуемым спросом, кандидаты на исключение из ассортимента.\n\nМатрица ABC/XYZ позволяет разработать дифференцированную стратегию управления запасами для разных групп товаров и оптимизировать оборотный капитал.', uzDescription: 'ABC/XYZ hisoboti — bu assortimentni aniqroq boshqarish uchun ikkita tasnifni birlashtiruvchi kompleks tahlil. Har bir tovarga qo\'sh toifa beriladi, masalan AX, BY, CZ.\n\nA toifa yuqori tushum va barqaror talabli tovarlarni birlashtiradi — bu har doim mavjud bo\'lishi kerak bo\'lgan asosiy pozitsiyalar. CZ toifa — kam hissa va bashorat qilib bo\'lmaydigan talabli tovarlar, assortimentdan chiqarish uchun nomzodlar.\n\nABC/XYZ matritsasi turli tovar guruhlari uchun zaxiralarni boshqarishning differensial strategiyasini ishlab chiqish va aylanma kapitalni optimallashtirish imkonini beradi.', ruFunctionality: 'Строит матрицу ABC/XYZ с распределением товаров по девяти категориям. Каждая ячейка матрицы показывает количество товаров и их суммарный вклад в выручку.\n\nМожно детализировать матрицу до списка конкретных товаров в каждой категории. Это помогает принять решения по управлению конкретными позициями.\n\nОтчёт рекомендует стратегии управления для каждой категории: методы прогнозирования, размер страхового запаса, частоту пополнения.', uzFunctionality: 'Tovarlarni to\'qqiz toifaga bo\'lish bilan ABC/XYZ matritsasini tuzadi. Matritsaning har bir katakchasi tovarlar sonini va ularning tushumga umumiy hissasini ko\'rsatadi.\n\nMatritsani har bir toifadagi aniq tovarlar ro\'yxatigacha batafsil ko\'rish mumkin. Bu aniq pozitsiyalarni boshqarish bo\'yicha qarorlar qabul qilishga yordam beradi.\n\nHisobot har bir toifa uchun boshqaruv strategiyalarini tavsiya qiladi: prognozlash usullari, sug\'urta zaxirasi hajmi, to\'ldirish chastotasi.' },

  { order: 174, ruDescription: 'Отчёт по параметрам позволяет анализировать продажи по атрибутам товаров: цвету, размеру, материалу и другим характеристикам. Это важно для товаров с вариациями.\n\nОтчёт показывает, какие модификации товаров пользуются наибольшим спросом, а какие — залёживаются. Это помогает принимать решения о закупках и формировании ассортимента.\n\nАнализ по параметрам особенно полезен для одежды, обуви, электроники и других категорий, где характеристики влияют на спрос. Можно выявить тренды по цветам или размерам.', uzDescription: 'Parametrlar hisoboti tovarlarning atributlari bo\'yicha sotuvlarni tahlil qilish imkonini beradi: rang, o\'lcham, material va boshqa xususiyatlar. Bu o\'zgaruvchan tovarlar uchun muhim.\n\nHisobot qaysi tovar modifikatsiyalari eng ko\'p talabga ega ekanligini va qaysilari yotib qolganini ko\'rsatadi. Bu xaridlar va assortimentni shakllantirish bo\'yicha qarorlar qabul qilishga yordam beradi.\n\nParametrlar bo\'yicha tahlil kiyim, poyabzal, elektronika va boshqa xususiyatlar talabga ta\'sir qiladigan kategoriyalar uchun ayniqsa foydali. Ranglar yoki o\'lchamlar bo\'yicha tendensiyalarni aniqlash mumkin.' , ruFunctionality: 'Группирует данные о продажах по выбранным параметрам товаров. Можно выбрать один или несколько параметров для перекрёстного анализа, например, цвет и размер.\n\nРезультаты отображаются в виде таблицы и графика с возможностью сортировки по объёму продаж. Параметры с наилучшими показателями выделяются визуально.\n\nОтчёт позволяет быстро определить популярные и непопулярные модификации для корректировки закупочной политики.', uzFunctionality: 'Sotuvlar ma\'lumotlarini tanlangan tovar parametrlari bo\'yicha guruhlaydi. Chiziqli tahlil uchun bitta yoki bir nechta parametrni tanlash mumkin, masalan, rang va o\'lcham.\n\nNatijalar sotuvlar hajmi bo\'yicha saralash imkoniyati bilan jadval va grafik ko\'rinishida ko\'rsatiladi. Eng yaxshi ko\'rsatkichli parametrlar vizual ajratib ko\'rsatiladi.\n\nHisobot xarid siyosatini tuzatish uchun ommabop va ommabop bo\'lmagan modifikatsiyalarni tez aniqlash imkonini beradi.' },

  { order: 175, ruDescription: 'Отчёт "Товары без движения" выявляет позиции, которые не продавались в течение указанного периода. Это инструмент для выявления неликвидов и оптимизации ассортимента.\n\nТовары без движения могут свидетельствовать о проблемах: завышенные цены, низкое качество, отсутствие спроса. Анализ причин позволяет принять меры: снизить цену, провести акцию или исключить из ассортимента.\n\nРегулярный мониторинг товаров без движения помогает освободить складские площади и оборотный капитал, замороженный в неликвидах. Это особенно важно для скоропортящихся товаров.', uzDescription: '"Harakatsiz tovarlar" hisoboti ko\'rsatilgan davr mobaynida sotilmagan pozitsiyalarni aniqlaydi. Bu no-likvidlarni aniqlash va assortimentni optimallashtirish uchun vosita.\n\nHarakatsiz tovarlar muammolar haqida guvohlik berishi mumkin: haddan tashqari yuqori narxlar, past sifat, talab yo\'qligi. Sabablarni tahlil qilish choralarni ko\'rish imkonini beradi: narxni pasaytirish, aksiya o\'tkazish yoki assortimentdan chiqarish.\n\nHarakatsiz tovarlarni muntazam kuzatish ombor maydonlarini va no-likvidlarga muzlatilgan aylanma kapitalni bo\'shatishga yordam beradi. Bu ayniqsa tez buziladigan tovarlar uchun muhim.', ruFunctionality: 'Отображает список товаров, по которым не было продаж за выбранный период. Можно настроить период анализа и дополнительные фильтры по категориям или складам.\n\nДля каждого товара показывается последний день продажи, текущий остаток и его стоимость. Это помогает оценить масштаб проблемы и приоритеты работы с неликвидами.\n\nОтчёт можно выгрузить для работы с менеджерами или планирования распродаж. Система также рекомендует действия по работе с неликвидами.', uzFunctionality: 'Tanlangan davr mobaynida sotuvi bo\'lmagan tovarlar ro\'yxatini ko\'rsatadi. Tahlil davrini va kategoriyalar yoki omborlar bo\'yicha qo\'shimcha filtrlarni sozlash mumkin.\n\nHar bir tovar uchun oxirgi sotuv kuni, joriy qoldiq va uning qiymati ko\'rsatiladi. Bu muammo hajmini va no-likvidlar bilan ishlash ustuvorliklarini baholashga yordam beradi.\n\nHisobotni menejerlar bilan ishlash yoki savdolarni rejalashtirish uchun yuklab olish mumkin. Tizim shuningdek no-likvidlar bilan ishlash bo\'yicha harakatlarni tavsiya qiladi.' },

  // === НАСТРОЙКИ: ОПЛАТА (176-177) ===
  { order: 176, ruDescription: 'Раздел "Методы оплаты" предназначен для настройки способов приёма платежей от покупателей. Это важный элемент конфигурации кассовой системы.\n\nВ разделе отображается список настроенных методов оплаты: наличные, банковские карты, электронные кошельки, кредит. Каждый метод имеет свои параметры и условия использования.\n\nПравильная настройка методов оплаты обеспечивает корректный учёт денежных средств и удобство расчётов с покупателями. Можно ограничить использование методов по сумме или другим условиям.', uzDescription: '"To\'lov usullari" bo\'limi xaridorlardan to\'lovlarni qabul qilish usullarini sozlash uchun mo\'ljallangan. Bu kassa tizimini sozlashning muhim elementi.\n\nBo\'limda sozlangan to\'lov usullari ro\'yxati ko\'rsatiladi: naqd pul, bank kartalari, elektron hamyonlar, kredit. Har bir usul o\'z parametrlari va foydalanish shartlariga ega.\n\nTo\'lov usullarini to\'g\'ri sozlash pul mablag\'larining to\'g\'ri hisobini va xaridorlar bilan hisob-kitoblar qulayligini ta\'minlaydi. Usullardan foydalanishni summa yoki boshqa shartlar bo\'yicha cheklash mumkin.', ruFunctionality: 'Открывает список способов приёма платежей с возможностью добавления, редактирования и удаления. Система поддерживает интеграцию с платёжными терминалами и системами быстрых платежей.\n\nДля каждого метода можно настроить параметры: комиссия, сдача, реквизиты счёта зачисления. Также можно указать, в каких точках продаж доступен данный метод.\n\nНастройки методов оплаты применяются во всех режимах расчёта: касса, реализация, оплата от контрагента.', uzFunctionality: 'Qo\'shish, tahrirlash va o\'chirish imkoniyati bilan to\'lovlarni qabul qilish usullari ro\'yxatini ochadi. Tizim to\'lov terminallari va tez to\'lov tizimlari bilan integratsiyani qo\'llab-quvvatlaydi.\n\nHar bir usul uchun parametrlarni sozlash mumkin: komissiya, qaytarilgan pul, hisobga olish rekvizitlari. Shuningdek ushbu usul qaysi savdo nuqtalarida mavjudligini ko\'rsatish mumkin.\n\nTo\'lov usullari sozlamalari barcha hisob-kitob rejimlarida qo\'llaniladi: kassa, realizatsiya, kontragentdan to\'lov.' },

  { order: 177, ruDescription: 'Кнопка добавления метода оплаты позволяет создать новый способ приёма платежей. Это необходимо при расширении возможностей расчётов с покупателями.\n\nПри добавлении метода нужно указать его название, тип (наличные, карта, электронный), и параметры зачисления средств. Для безналичных методов требуются реквизиты счёта.\n\nНовый метод оплаты сразу становится доступен для выбора при оформлении чеков и других расчётных операций. Можно настроить ограничения по сумме и условиям использования.', uzDescription: 'To\'lov usulini qo\'shish tugmasi to\'lovlarni qabul qilishning yangi usulini yaratish imkonini beradi. Bu xaridorlar bilan hisob-kitob imkoniyatlarini kengaytirishda zarur.\n\nUsul qo\'shilganda uning nomini, turini (naqd pul, karta, elektron) va mablag\'larni hisobga olish parametrlarini ko\'rsatish kerak. Naqd pulsiz usullar uchun hisob rekvizitlari talab qilinadi.\n\nYangi to\'lov usuli darhol cheklarni rasmiylashtirish va boshqa hisob-kitob operatsiyalarida tanlash uchun mavjud bo\'ladi. Summa va foydalanish shartlari bo\'yicha cheklovlarni sozlash mumkin.', ruFunctionality: 'Открывает форму создания нового способа оплаты с выбором типа и настройкой параметров. Форма содержит поля для всех необходимых данных в зависимости от типа метода.\n\nДля банковских карт можно настроить интеграцию с платёжным шлюзом для автоматического списания. Для электронных кошельков — указать идентификаторы и токены.\n\nПосле сохранения новый метод появляется в списке и готов к использованию в кассовых операциях.', uzFunctionality: 'Turini tanlash va parametrlarni sozlash bilan yangi to\'lov usulini yaratish formasini ochadi. Forma usul turiga qarab barcha kerakli ma\'lumotlar uchun maydonlarni o\'z ichiga oladi.\n\nBank kartalari uchun avtomatik yozib chiqarish uchun to\'lov shlyuzi bilan integratsiyani sozlash mumkin. Elektron hamyonlar uchun — identifikatorlar va tokenlarni ko\'rsatish.\n\nSaqlangandan so\'ng yangi usul ro\'yxatda paydo bo\'ladi va kassa operatsiyalarida foydalanishga tayyor bo\'ladi.' },

  // === НАСТРОЙКИ: ПЕЧАТЬ (178-180) ===
  { order: 178, ruDescription: 'Раздел "Ценники" предназначен для настройки шаблонов и параметров печати ценников на товары. Это необходимо для оформления торгового зала в соответствии с законодательством.\n\nВ разделе можно выбрать размер ценника, шаблон оформления и информацию, которая будет отображаться. Доступны стандартные шаблоны и возможность создания собственных.\n\nНастройка ценников позволяет автоматически формировать и печатать ценники с актуальными ценами при их изменении. Это экономит время и исключает ошибки при ручном оформлении.', uzDescription: '"Narx yorliqlari" bo\'limi tovarlar uchun narx yorliqlarini chop etish shablonlari va parametrlarini sozlash uchun mo\'ljallangan. Bu qonunchilikka muvofiq savdo zalini bezash uchun zarur.\n\nBo\'limda narx yorlig\'i o\'lchamini, dizayn shabloni va ko\'rsatiladigan ma\'lumotni tanlash mumkin. Standart shablonlar va o\'z shablonlarini yaratish imkoniyati mavjud.\n\nNarx yorliqlarini sozlash narxlar o\'zgarganda ular bilan avtomatik shakllantirish va narx yorliqlarini chop etish imkonini beradi. Bu vaqtni tejaydi va qo\'lda rasmiylashtirishda xatolarni istisno qiladi.', ruFunctionality: 'Открывает настройки печати ценников с выбором формата, шаблона и параметров отображения. Можно настроить печать на различных типах носителей: обычная бумага, самоклеящиеся этикетки.\n\nДля шаблона настраивается состав информации: наименование, цена, единица измерения, штрих-код, дата. Порядок и размер элементов можно менять перетаскиванием.\n\nПредпросмотр показывает, как будет выглядеть ценник перед печатью. Можно настроить автоматическую печать при изменении цен.', uzFunctionality: 'Formatni, shablonni va ko\'rsatish parametrlarini tanlash bilan narx yorliqlarini chop etish sozlamalarini ochadi. Turli xil tashuvchilarda chop etishni sozlash mumkin: oddiy qog\'oz, o\'z-o\'zidan yopishqoq etiketkalar.\n\nShablon uchun ma\'lumotlar tarkibi sozlanadi: nom, narx, o\'lchov birligi, shtrix-kod, sana. Elementlar tartibini va o\'lchamini sudrab o\'zgartirish mumkin.\n\nOldindan ko\'rish chop etishdan oldin narx yorlig\'i qanday ko\'rinishini ko\'rsatadi. Narxlar o\'zgarganda avtomatik chop etishni sozlash mumkin.' },

  { order: 179, ruDescription: 'Раздел "Чеки" предназначен для настройки параметров печати кассовых чеков. Это важный элемент соответствия требованиям фискализации и законодательства.\n\nВ разделе настраивается формат чека, состав выводимой информации и параметры принтера. Можно добавить обязательные реквизиты: ИНН, адрес, режим налогообложения.\n\nПравильная настройка чеков обеспечивает соблюдение требований законодательства о применении контрольно-кассовой техники и защите прав потребителей.', uzDescription: '"Cheklar" bo\'limi kassa cheklarini chop etish parametrlarini sozlash uchun mo\'ljallangan. Bu fiskalizatsiya va qonunchilik talablariga muvofiqlikning muhim elementi.\n\nBo\'limda chek formati, chiqariladigan ma\'lumotlar tarkibi va printer parametrlari sozlanadi. Majburiy rekvizitlarni qo\'shish mumkin: INN, manzil, soliqqa tortish rejimi.\n\nCheklarni to\'g\'ri sozlash nazorat-kassa texnikasini qo\'llash va iste\'molchilar huquqlarini himoya qilish to\'g\'risidagi qonunchilik talablariga rioya qilishni ta\'minlaydi.', ruFunctionality: 'Открывает параметры настройки кассовых чеков: ширина бумаги, состав реквизитов, порядок строк. Все изменения сразу отображаются в предпросмотре.\n\nМожно настроить автоматическую печать копии чека для архива или отправку электронной копии покупателю. Также настраивается печать QR-кода с данными чека.\n\nДля фискальных регистраторов доступны специальные настройки: режим работы, параметры фискализации, таймауты.', uzFunctionality: 'Kassa cheklari sozlamalari parametrlarini ochadi: qog\'oz kengligi, rekvizitlar tarkibi, qatorlar tartibi. Barcha o\'zgarishlar darhol oldindan ko\'rishda ko\'rsatiladi.\n\nArxiv uchun chekning nusxasini avtomatik chop etishni yoki elektron nusxani xaridorga yuborishni sozlash mumkin. Shuningdek chek ma\'lumotlari bilan QR-kod chop etish sozlanadi.\n\nFiskal registratorlar uchun maxsus sozlamalar mavjud: ish rejimi, fiskalizatsiya parametrlari, taymautlar.' },

  { order: 180, ruDescription: 'Функция загрузки логотипа позволяет добавить изображение компании на кассовый чек. Это элемент фирменного стиля и узнаваемости организации.\n\nЛоготип размещается в верхней части чека и печатается на каждом документе. Это повышает профессиональный имидж организации и помогает покупателям запомнить бренд.\n\nДля печати логотипа требуется принтер с поддержкой графической печати. Изображение должно быть в подходящем формате и разрешении для качественной печати.', uzDescription: 'Logotipni yuklash funksiyasi kompaniya tasvirini kassa chekiga qo\'shish imkonini beradi. Bu tashkilotning korporativ uslubi va tanilishining elementi.\n\nLogotip chekning yuqori qismida joylashtiriladi va har bir hujjatda chop etiladi. Bu tashkilotning professional obrozini oshiradi va xaridorlarga brendni eslab qolishga yordam beradi.\n\nLogotipni chop etish uchun grafik chop etishni qo\'llab-quvvatlaydigan printer kerak. Tasvir sifatli chop etish uchun mos format va o\'lchamda bo\'lishi kerak.', ruFunctionality: 'Открывает форму загрузки изображения логотипа с параметрами масштабирования и позиционирования. Поддерживаются форматы PNG, JPG, BMP.\n\nПосле загрузки логотип отображается в предпросмотре чека. Можно настроить размер и расположение относительно других элементов.\n\nИзменения вступают в силу при следующей печати чека. Можно удалить логотип, если он больше не нужен.', uzFunctionality: 'Masshtablashtirish va joylashtirish parametrlari bilan logotip tasvirini yuklash formasini ochadi. PNG, JPG, BMP formatlari qo\'llab-quvvatlanadi.\n\nYuklangandan so\'ng logotip chekning oldindan ko\'rishida ko\'rsatiladi. Boshqa elementlarga nisbatan o\'lcham va joylashishni sozlash mumkin.\n\nO\'zgarishlar keyingi chek chop etilganda kuchga kiradi. Agar logotip kerak bo\'lmasa, uni o\'chirish mumkin.' },

  // === НАСТРОЙКИ: ОБОРУДОВАНИЕ (181-182) ===
  { order: 181, ruDescription: 'Раздел "Устройства" предназначен для управления подключённым оборудованием: кассами, принтерами, сканерами, весами. Это центральный пункт настройки аппаратной части системы.\n\nВ разделе отображается список всех подключённых устройств с информацией о их состоянии и настройках. Можно добавить новое устройство или изменить параметры существующего.\n\nПравильная настройка оборудования обеспечивает бесперебойную работу системы и корректное взаимодействие всех компонентов. Система автоматически определяет некоторые типы оборудования.', uzDescription: '"Qurilmalar" bo\'limi ulangan uskunani boshqarish uchun mo\'ljallangan: kassalar, printerlar, skanerlar, tarozilar. Bu tizimning apparat qismini sozlashning markaziy punkti.\n\nBo\'limda ularning holati va sozlamalari haqida ma\'lumot bilan barcha ulangan qurilmalar ro\'yxati ko\'rsatiladi. Yangi qurilma qo\'shish yoki mavjud parametrlarni o\'zgartirish mumkin.\n\nUskuna to\'g\'ri sozlanganda tizimning uzluksiz ishlashi va barcha komponentlarning to\'g\'ri o\'zaro ta\'siri ta\'minlanadi. Tizim ba\'zi qurilma turlarini avtomatik aniqlaydi.', ruFunctionality: 'Открывает список подключённых устройств с возможностью добавления, настройки и удаления. Для каждого устройства отображается тип, модель, статус подключения и доступные действия.\n\nМожно протестировать работу устройства прямо из интерфейса: печать тестовой страницы, сканирование штрих-кода, проверка связи. Это помогает быстро выявить проблемы.\n\nДля каждого типа устройств доступны специфические настройки: скорость печати, звуковые сигналы, режимы работы.', uzFunctionality: 'Qo\'shish, sozlash va o\'chirish imkoniyati bilan ulangan qurilmalar ro\'yxatini ochadi. Har bir qurilma uchun tur, model, ulanish holati va mavjud harakatlar ko\'rsatiladi.\n\nInterfeysdan to\'g\'ridan-to\'g\'ri qurilma ishini sinab ko\'rish mumkin: sinov sahifasini chop etish, shtrix-kodni skanerlash, aloqani tekshirish. Bu muammolarni tez aniqlashga yordam beradi.\n\nHar bir qurilma turi uchun o\'ziga xos sozlamalar mavjud: chop etish tezligi, ovoz signallari, ish rejimlari.' },

  { order: 182, ruDescription: 'Кнопка добавления устройства открывает форму для подключения нового оборудования к системе. Это необходимо при расширении парка техники или замене устройств.\n\nПри добавлении нужно выбрать тип устройства, указать модель и параметры подключения. Система поддерживает широкий спектр оборудования от различных производителей.\n\nПосле добавления устройство становится доступным для использования во всех соответствующих операциях системы. Можно настроить, для каких точек продаж или операций устройство активно.', uzDescription: 'Qurilma qo\'shish tugmasi tizimga yangi uskuna ulash formasini ochadi. Bu texnika parkini kengaytirishda yoki qurilmalarni almashtirishda zarur.\n\nQo\'shishda qurilma turini tanlash, model va ulanish parametrlarini ko\'rsatish kerak. Tizim turli ishlab chiqaruvchilarning keng doiradagi uskunalarini qo\'llab-quvvatlaydi.\n\nQo\'shilgandan so\'ng qurilma tizimning barcha tegishli operatsiyalarida foydalanish uchun mavjud bo\'ladi. Qaysi savdo nuqtalari yoki operatsiyalar uchun qurilma faol ekanligini sozlash mumkin.', ruFunctionality: 'Открывает мастер добавления устройства с пошаговой настройкой. На первом этапе выбирается тип устройства, на втором — модель и параметры подключения.\n\nСистема автоматически сканирует доступные устройства и предлагает варианты для подключения. Для некоторых моделей доступна автоматическая настройка параметров.\n\nПосле сохранения устройство проходит тестирование и добавляется в список активного оборудования с готовностью к работе.', uzFunctionality: 'Bosqichma-bosqich sozlash bilan qurilma qo\'shish ustasini ochadi. Birinchi bosqichda qurilma turi tanlanadi, ikkinchisida — model va ulanish parametrlari.\n\nTizim mavjud qurilmalarni avtomatik skan qiladi va ulanish uchun variantlarni taklif qiladi. Ba\'zi modellar uchun parametrlarni avtomatik sozlash mavjud.\n\nSaqlangandan so\'ng qurilma sinovdan o\'tkaziladi va ishlashga tayyorlik bilan faol uskunalar ro\'yxatiga qo\'shiladi.' },

  // === НАСТРОЙКИ: ЦЕНЫ И ПАРАМЕТРЫ (183-186) ===
  { order: 183, ruDescription: 'Раздел "Ценообразование" предназначен для настройки правил и стратегий формирования цен. Это важный инструмент для управления маржинальностью и конкурентоспособностью.\n\nВ разделе можно настроить правила расчёта цен: наценка от закупочной цены, минимальная и максимальная наценка, округление. Правила могут различаться для разных категорий товаров.\n\nАвтоматизация ценообразования упрощает работу при массовых закупках и обеспечивает единую ценовую политику. Можно настроить автоматический пересчёт цен при изменении закупочных.', uzDescription: '"Narx belgilash" bo\'limi narxlarni shakllantirish qoidalari va strategiyalarini sozlash uchun mo\'ljallangan. Bu marja va raqobatbardoshlikni boshqarish uchun muhim vosita.\n\nBo\'limda narxlarni hisoblash qoidalarini sozlash mumkin: xarid narxidan chegirma, minimal va maksimal chegirma, yaxlitlash. Qoidalar turli tovar kategoriyalari uchun farq qilishi mumkin.\n\nNarx belgilashni avtomatlashtirish ommaviy xaridlarda ishni soddalashtiradi va yagona narx siyosatini ta\'minlaydi. Xarid narxlari o\'zgarganda narxlarni avtomatik qayta hisoblashni sozlash mumkin.', ruFunctionality: 'Открывает настройки правил ценообразования с возможностью создания нескольких стратегий. Каждая стратегия может включать базовую наценку, коэффициенты для категорий и правила округления.\n\nМожно настроить автоматический расчёт цены при поступлении товара на основе закупочной цены и правил. Это ускоряет обработку больших партий товаров.\n\nТакже доступны правила для расчёта цен при переоценке: процент изменения, фиксация на уровне конкурентов.', uzFunctionality: 'Bir nechta strategiyani yaratish imkoniyati bilan narx belgilash qoidalari sozlamalarini ochadi. Har bir strategiya bazaviy chegirma, kategoriyalar uchun koeffitsientlar va yaxlitlash qoidalarini o\'z ichiga olishi mumkin.\n\nTovar kelib tushishida xarid narxi va qoidalar asosida narxni avtomatik hisoblashni sozlash mumkin. Bu katta tovar partiyalarini ishlashni tezlashtiradi.\n\nShuningdek qayta baholashda narxlarni hisoblash qoidalari mavjud: o\'zgarish foizi, raqobatchilar darajasida belgilash.' },

  { order: 184, ruDescription: 'Раздел "Параметры" предназначен для создания и управления дополнительными атрибутами товаров. Это позволяет расширить информацию о товарах для удобства поиска и анализа.\n\nПараметры могут быть разных типов: текстовые, числовые, списки значений. Примеры параметров: цвет, размер, материал, бренд, страна производства.\n\nИспользование параметров позволяет детализировать отчёты и фильтры по товарам. Покупатели могут искать товары по параметрам в интернет-магазине или терминале самообслуживания.', uzDescription: '"Parametrlar" bo\'limi tovarlarning qo\'shimcha atributlarini yaratish va boshqarish uchun mo\'ljallangan. Bu qidirish va tahlil qulayligi uchun tovarlar haqidagi ma\'lumotlarni kengaytirish imkonini beradi.\n\nParametrlar turli turlarda bo\'lishi mumkin: matn, raqam, qiymatlar ro\'yxati. Parametr misollari: rang, o\'lcham, material, brend, ishlab chiqarish mamlakati.\n\nParametrlardan foydalanish hisobotlar va tovarlar bo\'yicha filtrlarni batafsil ko\'rish imkonini beradi. Xaridorlar internet-do\'konda yoki o\'z-o\'ziga xizmat ko\'rsatish terminalida tovarlarni parametrlar bo\'yicha qidirishlari mumkin.', ruFunctionality: 'Открывает список параметров товаров с возможностью создания новых и редактирования существующих. Для каждого параметра указывается тип, название и список возможных значений.\n\nПараметры привязываются к категориям товаров для упорядочивания. При редактировании товара отображаются параметры, относящиеся к его категории.\n\nЗначения параметров используются в фильтрах, отчётах и при поиске товаров. Можно настроить обязательность заполнения параметров.', uzFunctionality: 'Yangilarini yaratish va mavjudlarni tahrirlash imkoniyati bilan tovar parametrlari ro\'yxatini ochadi. Har bir parametr uchun tur, nom va mumkin bo\'lgan qiymatlar ro\'yxati ko\'rsatiladi.\n\nParametrlar tartiblash uchun tovar kategoriyalariga bog\'lanadi. Tovarni tahrirlashda uning kategoriyasiga tegishli parametrlar ko\'rsatiladi.\n\nParametr qiymatlari filtrlarda, hisobotlarda va tovarlarni qidirishda ishlatiladi. Parametrlarni to\'ldirish majburiyligini sozlash mumkin.' },

  { order: 185, ruDescription: 'Раздел "Теги" предназначен для создания и управления метками для категоризации товаров и других объектов. Теги — это гибкий инструмент для группировки по произвольным признакам.\n\nВ отличие от категорий, товар может иметь несколько тегов одновременно. Это позволяет создавать пересекающиеся группы: "новинки", "акция", "хит продаж", "без глютена".\n\nИспользование тегов упрощает поиск и фильтрацию, а также позволяет создавать динамические подборки товаров для акций и маркетинга.', uzDescription: '"Teglar" bo\'limi tovarlar va boshqa ob\'ektlarni kategoriyalash uchun yorliqlar yaratish va boshqarish uchun mo\'ljallangan. Teglar — bu ixtiyoriy belgilarga ko\'ra guruhlash uchun moslashuvchan vosita.\n\nKategoriyalardan farqli o\'laroq, tovar bir vaqtning o\'zida bir nechta tegga ega bo\'lishi mumkin. Bu kesishuvchi guruhlarni yaratish imkonini beradi: "yangiliklar", "aksiya", "sotuv hiti", "glutensiz".\n\nTeglardan foydalanish qidirish va filtrlashni soddalashtiradi, shuningdek aksiyalar va marketing uchun tovarlarning dinamik tanlovlarini yaratish imkonini beradi.', ruFunctionality: 'Открывает список тегов с возможностью создания, редактирования и удаления. Для каждого тега указывается название и цвет для визуального отличия.\n\nТеги можно присваивать товарам, контрагентам, документам и другим объектам. Присвоение выполняется через интерфейс карточки объекта.\n\nНа основе тегов работают фильтры в списках и условия в автоматических правилах. Можно настроить уведомления при появлении объектов с определёнными тегами.', uzFunctionality: 'Yaratish, tahrirlash va o\'chirish imkoniyati bilan teglar ro\'yxatini ochadi. Har bir teg uchun nom va vizual farqlash uchun rang ko\'rsatiladi.\n\nTeglarni tovarlarga, kontragentlarga, hujjatlarga va boshqa ob\'ektlarga biriktirish mumkin. Biriktirish ob\'ekt kartochkasi interfeysi orqali amalga oshiriladi.\n\nTeglar asosida ro\'yxatlardagi filtrlar va avtomatik qoidalardagi shartlar ishlaydi. Aniq teglar bo\'lgan ob\'ektlar paydo bo\'lganda bildirishnomalarni sozlash mumkin.' },

  { order: 186, ruDescription: 'Раздел "Интерфейс" предназначен для настройки внешнего вида и поведения системы. Это позволяет адаптировать программу под индивидуальные предпочтения пользователя.\n\nВ разделе можно выбрать тему оформления, размер шрифта, цветовую схему. Доступны светлая и тёмная темы, а также настройки для людей с нарушениями зрения.\n\nПерсонализация интерфейса повышает комфорт работы и снижает утомляемость при длительном использовании системы. Настройки сохраняются для каждого пользователя отдельно.', uzDescription: '"Interfeys" bo\'limi tizimning tashqi ko\'rinishi va xatti-harakatlarini sozlash uchun mo\'ljallangan. Bu dasturni foydalanuvchining shaxsiy afzalliklariga moslashtirish imkonini beradi.\n\nBo\'limda dizayn mavzusini, shrift o\'lchamini, rang sxemasini tanlash mumkin. Ochiq va qorong\'i mavzular, shuningdek ko\'rish buzilishi bo\'lgan odamlar uchun sozlamalar mavjud.\n\nInterfeysni shaxsiylashtirish ishlash qulayligini oshiradi va tizimdan uzoq foydalanishda charchashni kamaytiradi. Sozlamalar har bir foydalanuvchi uchun alohida saqlanadi.', ruFunctionality: 'Открывает панель настроек интерфейса с предпросмотром изменений. Можно сразу видеть, как будут выглядеть элементы при выбранных настройках.\n\nДоступны настройки темы (светлая/тёмная/авто), основного цвета акцента, размера шрифта и плотности отображения элементов. Также можно настроить поведение бокового меню.\n\nИзменения применяются мгновенно без перезагрузки страницы. Можно сбросить все настройки к значениям по умолчанию.', uzFunctionality: 'O\'zgarishlarni oldindan ko\'rish bilan interfeys sozlamalari panelini ochadi. Tanlangan sozlamalarda elementlar qanday ko\'rinib turganini darhol ko\'rish mumkin.\n\nMavzu (ochiq/qorong\'i/avto), asosiy aksent rang, shrift o\'lchami va elementlarni ko\'rsatish zichligi sozlamalari mavjud. Shuningdek yon menyu xatti-harakatlarini sozlash mumkin.\n\nO\'zgarishlar sahifani qayta yuklamasdan darhol qo\'llaniladi. Barcha sozlamalarni standart qiymatlarga qaytarish mumkin.' },

  // === НАСТРОЙКИ: ИНТЕГРАЦИИ (187-192) ===
  { order: 187, ruDescription: 'Функция смены языка позволяет переключить интерфейс системы между доступными языками. Это важно для работы в многонациональных коллективах.\n\nСистема поддерживает русский и узбекский языки. Все элементы интерфейса, сообщения и справка переводятся на выбранный язык.\n\nВыбор языка влияет только на отображение интерфейса и не меняет данные в базе. Наименования товаров и другие введённые данные остаются на языке ввода.', uzDescription: 'Tilni o\'zgartirish funksiyasi interfeysni mavjud tillar o\'rtasida o\'tkazish imkonini beradi. Bu ko\'p millatli jamoalarda ishlash uchun muhim.\n\nTizim rus va o\'zbek tillarini qo\'llab-quvvatlaydi. Barcha interfeys elementlari, xabarlar va yordam tanlangan tilga tarjima qilinadi.\n\nTil tanlash faqat interfeys ko\'rinishiga ta\'sir qiladi va bazadagi ma\'lumotlarni o\'zgartirmaydi. Tovar nomlari va boshqa kiritilgan ma\'lumotlar kiritilgan tilida qoladi.', ruFunctionality: 'Открывает выпадающий список доступных языков для мгновенного переключения. После выбора языка интерфейс обновляется без перезагрузки страницы.\n\nВыбранный язык сохраняется в настройках пользователя и применяется при следующем входе. Каждый пользователь может выбрать свой язык независимо от других.\n\nЯзык интерфейса также влияет на форматы дат, чисел и валют для соответствия региональным стандартам.', uzFunctionality: 'Bir zumda o\'tkazish uchun mavjud tillarning ochiladigan ro\'yxatini ochadi. Til tanlangandan so\'ng interfeys sahifani qayta yuklamasdan yangilanadi.\n\nTanlangan til foydalanuvchi sozlamalarida saqlanadi va keyingi kirishda qo\'llaniladi. Har bir foydalanuvchi o\'z tilini boshqalardan mustaqil tanlashi mumkin.\n\nInterfeys tili shuningdek mintaqaviy standartlarga muvofiqligi uchun sanalar, sonlar va valyutalarning formatlariga ta\'sir qiladi.' },

  { order: 188, ruDescription: 'Раздел "Телеграм бот" предназначен для настройки интеграции с мессенджером Telegram для получения уведомлений. Это современный способ оперативного информирования.\n\nБот может отправлять уведомления о новых заказах, низких остатках, завершении смены и других событиях. Настройка позволяет выбрать типы событий для уведомлений.\n\nИспользование Telegram бота обеспечивает мгновенное получение важной информации на мобильное устройство. Это особенно полезно для менеджеров и руководителей.', uzDescription: '"Telegram bot" bo\'limi bildirishnomalarni olish uchun Telegram messenjeri bilan integratsiyani sozlash uchun mo\'ljallangan. Bu tezkor ma\'lumot berishning zamonaviy usuli.\n\nBot yangi buyurtmalar, past qoldiqlar, smena tugashi va boshqa hodisalar haqida bildirishnomalar yuborishi mumkin. Sozlash bildirishnomalar uchun hodisa turlarini tanlash imkonini beradi.\n\nTelegram botidan foydalanish muhim ma\'lumotlarni mobil qurilmaga bir zumda olishni ta\'minlaydi. Bu ayniqsa menejerlar va rahbarlar uchun foydali.', ruFunctionality: 'Открывает настройки Telegram бота с возможностью подключения, отключения и настройки типов уведомлений. Статус подключения показывает, активен ли бот.\n\nМожно настроить, какие события будут вызывать уведомления: продажи, возвраты, инкассация, низкие остатки. Для каждого типа настраивается порог и периодичность.\n\nТакже можно добавить нескольких получателей уведомлений — разных сотрудников или группы. Это обеспечивает адресную доставку информации.', uzFunctionality: 'Ulanish, uzish va bildirishnoma turlarini sozlash imkoniyati bilan Telegram bot sozlamalarini ochadi. Ulanish holati bot faol yoki yo\'qligini ko\'rsatadi.\n\nQaysi hodisalar bildirishnoma keltirib chiqarishini sozlash mumkin: sotuvlar, qaytarishlar, inkassatsiya, past qoldiqlar. Har bir tur uchun chegirma va chastotani sozlash mumkin.\n\nShuningdek bir nechta bildirishnoma oluvchilarni — turli xodimlar yoki guruhlarni qo\'shish mumkin. Bu ma\'lumotlarni manzilli yetkazishni ta\'minlaydi.' },

  { order: 189, ruDescription: 'Кнопка подключения бота инициирует процесс связывания системы с Telegram ботом. Это первый шаг для настройки уведомлений через мессенджер.\n\nПри нажатии открывается инструкция с ссылкой на бота и кодом авторизации. Нужно открыть бота в Telegram и отправить код для привязки аккаунта.\n\nПосле успешного подключения система получает возможность отправлять уведомления в Telegram. Статус подключения меняется на "Активен".', uzDescription: 'Botni ulash tugmasi tizimni Telegram bot bilan bog\'lash jarayonini boshlaydi. Bu messenjer orqali bildirishnomalarni sozlash uchun birinchi qadam.\n\nBosilganda botga havola va avtorizatsiya kodi bilan ko\'rsatma ochiladi. Telegramda botni ochish va hisobni bog\'lash uchun kodni yuborish kerak.\n\nMuvaffaqiyatli ulangandan so\'ng tizim Telegramga bildirishnomalar yuborish qobiliyatiga ega bo\'ladi. Ulanish holati "Faol" ga o\'zgaradi.', ruFunctionality: 'Открывает модальное окно с пошаговой инструкцией подключения. На первом шаге показывается ссылка на бота, на втором — код для отправки боту.\n\nСистема ожидает подтверждения от бота и автоматически завершает подключение при получении правильного кода. Весь процесс занимает менее минуты.\n\nПри возникновении проблем показывается подсказка с возможными решениями. Можно отменить подключение и начать заново.', uzFunctionality: 'Bosqichma-bosqich ulash ko\'rsatmasi bilan modal oynani ochadi. Birinchi qadamda botga havola ko\'rsatiladi, ikkinchisida — botga yuborish uchun kod.\n\nTizim botdan tasdiqlashni kutadi va to\'g\'ri kod kelganda ulashni avtomatik yakunlaydi. Butun jarayon bir daqiqadan kam vaqt oladi.\n\nMuammo yuzaga kelganda mumkin bo\'lgan yechimlar bilan maslahat ko\'rsatiladi. Ulanishni bekor qilish va qaytadan boshlash mumkin.' },

  { order: 190, ruDescription: 'Раздел "Тарифы" показывает информацию о текущем тарифном плане и доступных опциях. Это важно для понимания ограничений и возможностей системы.\n\nВ разделе отображается название текущего тарифа, его стоимость, срок действия и включённые функции. Также показывается статистика использования лимитов.\n\nПри необходимости можно сравнить тарифы и выбрать оптимальный для потребностей организации. Информация о тарифах помогает планировать расходы на программное обеспечение.', uzDescription: '"Tariflar" bo\'limi joriy tarif rejasining va mavjud imkoniyatlarning ma\'lumotini ko\'rsatadi. Bu tizimning cheklovlari va imkoniyatlarini tushunish uchun muhim.\n\nBo\'limda joriy tarif nomi, uning narxi, amal qilish muddati va kiritilgan funksiyalar ko\'rsatiladi. Shuningdek limitlardan foydalanish statistikasi ham ko\'rsatiladi.\n\nZarurat bo\'lganda tariflarni solishtirish va tashkilot ehtiyojlariga mos keladiganini tanlash mumkin. Tariflar haqidagi ma\'lumotlar dasturiy ta\'minotga xarajatlarni rejalashtirishga yordam beradi.', ruFunctionality: 'Открывает страницу с информацией о текущем тарифе и списком всех доступных тарифных планов. Для каждого тарифа показаны функции, ограничения и стоимость.\n\nТекущий тариф выделяется, показывается дата следующего списания и остаток дней до продления. Можно посмотреть историю смены тарифов.\n\nПри приближении к лимитам тарифа система показывает предупреждение с рекомендацией по переходу на более высокий тариф.', uzFunctionality: 'Joriy tarif haqida ma\'lumot va barcha mavjud tarif rejalari ro\'yxati bilan sahifani ochadi. Har bir tarif uchun funksiyalar, cheklovlar va narx ko\'rsatiladi.\n\nJoriy tarif ajratib ko\'rsatiladi, keyingi yozib olish sanasi va yangilashgacha qolgan kunlar soni ko\'rsatiladi. Tariflarni o\'zgartirish tarixini ko\'rish mumkin.\n\nTarif limitlariga yaqinlashganda tizim yuqori tarifga o\'tish bo\'yicha tavsiya bilan ogohlantirish ko\'rsatadi.' },

  { order: 191, ruDescription: 'Кнопка смены тарифа позволяет перейти на другой тарифный план. Это используется при изменении потребностей организации или расширении бизнеса.\n\nПри смене тарифа система показывает сравнение текущего и нового тарифа с указанием отличий. Стоимость пересчитывается пропорционально оставшемуся периоду.\n\nСмена тарифа вступает в силу немедленно после подтверждения. Все данные сохраняются, доступны новые функции согласно выбранному тарифу.', uzDescription: 'Tarifni o\'zgartirish tugmasi boshqa tarif rejasiga o\'tish imkonini beradi. Bu tashkilot ehtiyojlarining o\'zgarishida yoki biznesning kengayishida ishlatiladi.\n\nTarif o\'zgartirilganda tizim farqlarni ko\'rsatgan holda joriy va yangi tarifni solishtirishni ko\'rsatadi. Narx qolgan davrga mutanosib ravishda qayta hisoblanadi.\n\nTarif o\'zgartirish tasdiqlangandan so\'ng darhol kuchga kiradi. Barcha ma\'lumotlar saqlanib qoladi, tanlangan tarifga muvofiq yangi funksiyalar mavjud bo\'ladi.', ruFunctionality: 'Открывает форму выбора нового тарифа с расчётом стоимости перехода. Показывается разница в цене и дата следующего списания.\n\nМожно выбрать период оплаты: месяц, квартал или год с соответствующими скидками. При годовой оплате обычно предоставляется существенная экономия.\n\nПосле подтверждения тариф меняется мгновенно. При понижении тарифа некоторые функции могут стать недоступны, но данные сохраняются.', uzFunctionality: 'O\'tish narxini hisoblash bilan yangi tarifni tanlash formasini ochadi. Narxdagi farq va keyingi yozib olish sanasi ko\'rsatiladi.\n\nTo\'lov davrini tanlash mumkin: oy, chorak yoki yil tegishli chegirmalar bilan. Yillik to\'lovda odatda sezilarli tejash taqdim etiladi.\n\nTasdiqlangandan so\'ng tarif bir zumda o\'zgaradi. Tarifni tushirishda ba\'zi funksiyalar mavjud bo\'lmasligi mumkin, lekin ma\'lumotlar saqlanib qoladi.' },

  { order: 192, ruDescription: 'Раздел "Подписки" показывает список активных подписок и дополнительных услуг. Это важно для контроля регулярных платежей и доступных опций.\n\nВ разделе отображаются все подписки: основной тариф, дополнительные модули, интеграции. Для каждой подписки указана стоимость и периодичность списания.\n\nУправление подписками позволяет добавлять или отключать дополнительные услуги в зависимости от потребностей. Это даёт гибкость в формировании функционала системы.', uzDescription: '"Obunalar" bo\'limi faol obunalar va qo\'shimcha xizmatlar ro\'yxatini ko\'rsatadi. Bu muntazam to\'lovlarni va mavjud imkoniyatlarni nazorat qilish uchun muhim.\n\nBo\'limda barcha obunalar ko\'rsatiladi: asosiy tarif, qo\'shimcha modullar, integratsiyalar. Har bir obuna uchun narx va yozib olish chastotasi ko\'rsatilgan.\n\nObunalarni boshqarish ehtiyojlarga qarab qo\'shimcha xizmatlarni qo\'shish yoki o\'chirish imkonini beradi. Bu tizim funksionalini shakllantirishda moslashuvchanlik beradi.', ruFunctionality: 'Открывает список всех подписок с возможностью управления каждой. Можно увидеть дату следующего списания, стоимость и статус для каждой подписки.\n\nДоступные дополнительные подписки показываются с описанием функций и стоимостью. Можно оформить подписку на дополнительный модуль или интеграцию.\n\nПри необходимости можно отменить подписку — она перестанет продлеваться, но функции останутся доступными до конца оплаченного периода.', uzFunctionality: 'Har birini boshqarish imkoniyati bilan barcha obunalar ro\'yxatini ochadi. Har bir obuna uchun keyingi yozib olish sanasi, narx va holatni ko\'rish mumkin.\n\nMavjud qo\'shimcha obunalar funksiyalar tavsifi va narxi bilan ko\'rsatiladi. Qo\'shimcha modul yoki integratsiyaga obuna bo\'lish mumkin.\n\nZarurat bo\'lganda obunani bekor qilish mumkin — u uzaytirilmaydi, lekin funksiyalar to\'langan davr oxirigacha mavjud bo\'lib qoladi.' },

  // === НАСТРОЙКИ: КАССЫ И КОМПАНИЯ (193-195) ===
  { order: 193, ruDescription: 'Раздел "Кассы" предназначен для управления кассовыми аппаратами и торговыми точками. Это центральный элемент настройки фискального учёта.\n\nВ разделе отображается список касс с информацией о модели, заводском номере, фискальном накопителе и статусе регистрации. Можно добавить новую кассу или изменить параметры существующей.\n\nПравильная настройка касс обеспечивает соответствие требованиям законодательства о применении контрольно-кассовой техники. Система интегрируется с основными производителями ККТ.', uzDescription: '"Kassalar" bo\'limi kassa apparatlarini va savdo nuqtalarini boshqarish uchun mo\'ljallangan. Bu fiskal hisobni sozlashning markaziy elementi.\n\nBo\'limda model, zavod raqami, fiskal sig\'im va ro\'yxatdan o\'tish holati haqida ma\'lumot bilan kassalar ro\'yxati ko\'rsatiladi. Yangi kassa qo\'shish yoki mavjud parametrlarni o\'zgartirish mumkin.\n\nKassalarni to\'g\'ri sozlash nazorat-kassa texnikasini qo\'llash to\'g\'risidagi qonunchilik talablariga muvofiqlikni ta\'minlaydi. Tizim KKT ning asosiy ishlab chiqaruvchilari bilan integratsiyalashadi.', ruFunctionality: 'Открывает список кассовых аппаратов с возможностью добавления, редактирования и мониторинга. Для каждой кассы показывается статус работы, остаток фискального накопителя и время последней операции.\n\nМожно провести технические операции с кассой: открытие/закрытие смены, печать отчётов, проверка связи. Для фискализированных касс доступны операции с фискальным накопителем.\n\nИнтеграция с ОФД обеспечивает автоматическую отправку данных в налоговую. Можно отследить статус доставки фискальных данных.', uzFunctionality: 'Qo\'shish, tahrirlash va kuzatish imkoniyati bilan kassa apparatlari ro\'yxatini ochadi. Har bir kassa uchun ish holati, fiskal sig\'im qoldig\'i va oxirgi operatsiya vaqti ko\'rsatiladi.\n\nKassa bilan texnik operatsiyalarni o\'tkazish mumkin: smenani ochish/yopish, hisobotlarni chop etish, aloqani tekshirish. Fiskalizatsiya qilingan kassalar uchun fiskal sig\'im bilan operatsiyalar mavjud.\n\nOFD bilan integratsiya ma\'lumotlarni soliq idorasiga avtomatik yuborishni ta\'minlaydi. Fiskal ma\'lumotlarni yetkazish holatini kuzatish mumkin.' },

  { order: 194, ruDescription: 'Раздел "Данные компании" содержит реквизиты организации, используемые в документах и отчётах. Это обязательная информация для правильного оформления документов.\n\nВ разделе указываются: название организации, ИНН, адрес, банковские реквизиты, контакты. Эти данные автоматически подставляются в печатные формы документов.\n\nКорректные реквизиты компании важны для соблюдения законодательства и правильного оформления расчётных документов. Данные используются во всех разделах системы.', uzDescription: '"Kompaniya ma\'lumotlari" bo\'limi hujjatlarda va hisobotlarda ishlatiladigan tashkilot rekvizitlarini o\'z ichiga oladi. Bu hujjatlarni to\'g\'ri rasmiylashtirish uchun majburiy ma\'lumot.\n\nBo\'limda ko\'rsatiladi: tashkilot nomi, INN, manzil, bank rekvizitlari, kontaktlar. Bu ma\'lumotlar avtomatik hujjatlarning bosma shakllariga qo\'yiladi.\n\nKompaniyaning to\'g\'ri rekvizitlari qonunchilikka rioya qilish va hisob-kitob hujjatlarini to\'g\'ri rasmiylashtirish uchun muhim. Ma\'lumotlar tizimning barcha bo\'limlarida ishlatiladi.', ruFunctionality: 'Открывает форму с полями для ввода реквизитов организации. Поля сгруппированы по категориям: общие данные, адрес, банковские реквизиты, контактная информация.\n\nМожно сохранить несколько банковских счетов и выбрать основной. Также доступна загрузка логотипа и печати для использования в документах.\n\nВведённые данные автоматически подставляются в накладные, чеки, счета и другие документы. При изменении данных новые документы будут использовать актуальную информацию.', uzFunctionality: 'Tashkilot rekvizitlarini kiritish uchun maydonli formani ochadi. Maydonlar kategoriyalar bo\'yicha guruhlangan: umumiy ma\'lumotlar, manzil, bank rekvizitlari, aloqa ma\'lumotlari.\n\nBir nechta bank hisoblarini saqlash va asosiyini tanlash mumkin. Shuningdek hujjatlarda foydalanish uchun logotip va muhrni yuklash mavjud.\n\nKiritilgan ma\'lumotlar avtomatik nakladnoylarga, cheklarga, hisoblarga va boshqa hujjatlarga qo\'yiladi. Ma\'lumotlar o\'zgarganda yangi hujjatlar dolzarb ma\'lumotlardan foydalanadi.' },

  { order: 195, ruDescription: 'Кнопка сохранения данных фиксирует введённые реквизиты компании в системе. Это финальный шаг при настройке или обновлении информации об организации.\n\nПри сохранении система проверяет корректность введённых данных: формат ИНН, наличие обязательных полей. При обнаружении ошибок показываются подсказки для исправления.\n\nПосле сохранения данные становятся доступными для использования во всех документах и отчётах. История изменений реквизитов сохраняется для аудита.', uzDescription: 'Ma\'lumotlarni saqlash tugmasi kiritilgan kompaniya rekvizitlarini tizimda belgilaydi. Bu tashkilot haqidagi ma\'lumotlarni sozlash yoki yangilashda yakuniy qadam.\n\nSaqlashda tizim kiritilgan ma\'lumotlarning to\'g\'riligini tekshiradi: INN formati, majburiy maydonlarning mavjudligi. Xatolar topilganda tuzatish uchun maslahatlar ko\'rsatiladi.\n\nSaqlangandan so\'ng ma\'lumotlar barcha hujjatlarda va hisobotlarda foydalanish uchun mavjud bo\'ladi. Rekvizitlar o\'zgarishlari tarixi auditoriya uchun saqlanadi.', ruFunctionality: 'Сохраняет реквизиты компании в базе данных с валидацией обязательных полей. При успешном сохранении показывается подтверждение с указанием изменённых данных.\n\nЕсли данные уже использовались в проведённых документах, система предупреждает о необходимости обновить шаблоны печатных форм. Новые документы сразу используют актуальные данные.\n\nМожно отменить несохранённые изменения и вернуться к предыдущим значениям до сохранения.', uzFunctionality: 'Majburiy maydonlarni tasdiqlash bilan kompaniya rekvizitlarini bazada saqlaydi. Muvaffaqiyatli saqlanganda o\'zgartirilgan ma\'lumotlar ko\'rsatilgan holda tasdiqlash ko\'rsatiladi.\n\nAgar ma\'lumotlar allaqachon o\'tkazilgan hujjatlarda ishlatilgan bo\'lsa, tizim bosma shakllar shablonlarini yangilash kerakligi haqida ogohlantiradi. Yangi hujjatlar darhol dolzarb ma\'lumotlardan foydalanadi.\n\nSaqlanmagan o\'zgarishlarni bekor qilish va saqlashdan oldin oldingi qiymatlarga qaytish mumkin.' },

  // === КАБИНЕТ: ЛИЧНЫЕ НАСТРОЙКИ (196-200) ===
  { order: 196, ruDescription: 'Раздел "Кабинет" — это личный кабинет пользователя с персональными настройками и информацией. Здесь пользователь управляет своим аккаунтом и предпочтениями.\n\nВ кабинете отображается информация о текущем пользователе: имя, email, роль, права доступа. Можно изменить личные данные, пароль и настройки уведомлений.\n\nЛичный кабинет также содержит историю действий пользователя и статистику работы в системе. Это помогает отслеживать свою активность и находить прошлые операции.', uzDescription: '"Kabinet" bo\'limi — bu shaxsiy sozlamalar va ma\'lumotlar bilan foydalanuvchining shaxsiy kabineti. Bu yerda foydalanuvchi o\'z akkauntini va afzalliklarini boshqaradi.\n\nKabinetda joriy foydalanuvchi haqida ma\'lumot ko\'rsatiladi: ism, email, rol, kirish huquqlari. Shaxsiy ma\'lumotlarni, parolni va bildirishnoma sozlamalarini o\'zgartirish mumkin.\n\nShaxsiy kabinet shuningdek foydalanuvchining harakatlar tarixi va tizimda ishlash statistikasini o\'z ichiga oladi. Bu o\'z faoliyatini kuzatish va o\'tgan operatsiyalarni topishga yordam beradi.', ruFunctionality: 'Открывает персональную страницу пользователя с информацией об аккаунте и настройками. Можно редактировать профиль, изменить пароль, настроить уведомления.\n\nСтраница показывает дату регистрации, последний вход и статистику активности. Администраторы также видят информацию о назначенных правах и ограничениях.\n\nИз кабинета можно перейти к истории входов, настройкам безопасности и другим персональным параметрам аккаунта.', uzFunctionality: 'Akkaunt haqida ma\'lumot va sozlamalar bilan foydalanuvchining shaxsiy sahifasini ochadi. Profilni tahrirlash, parolni o\'zgartirish, bildirishnomalarni sozlash mumkin.\n\nSahifa ro\'yxatdan o\'tish sanasi, oxirgi kirish va faollik statistikasini ko\'rsatadi. Administratorlar shuningdek belgilangan huquqlar va cheklovlar haqida ma\'lumotni ko\'rishadi.\n\nKabinetdan kirishlar tarixiga, xavfsizlik sozlamalariga va akkauntning boshqa shaxsiy parametrlariga o\'tish mumkin.' },

  { order: 197, ruDescription: 'Функция изменения пароля позволяет пользователю обновить пароль для входа в систему. Это важный элемент безопасности аккаунта.\n\nРекомендуется регулярно менять пароль и использовать надёжные комбинации: минимум 8 символов, буквы разного регистра, цифры и специальные знаки. Система проверяет сложность нового пароля.\n\nПосле смены пароля все активные сессии завершаются, и потребуется новый вход. Это защищает аккаунт при компрометации старого пароля.', uzDescription: 'Parolni o\'zgartirish funksiyasi foydalanuvchiga tizimga kirish parolini yangilash imkonini beradi. Bu akkaunt xavfsizligining muhim elementi.\n\nParolni muntazam o\'zgartirish va ishonchli kombinatsiyalardan foydalanish tavsiya etiladi: kamida 8 ta belgi, har xil registr harflari, raqamlar va maxsus belgilar. Tizim yangi parol murakkabligini tekshiradi.\n\nParol o\'zgartirilgandan so\'ng barcha faol sessiyalar tugatiladi va yangi kirish talab qilinadi. Bu eski parol oshkor bo\'lganda akkauntni himoya qiladi.', ruFunctionality: 'Открывает форму смены пароля с полями для текущего и нового пароля. Система проверяет соответствие текущего пароля и сложность нового.\n\nПри вводе нового пароля показывается индикатор его надёжности. Система не разрешает использовать слишком простые пароли или пароли, совпадающие с предыдущими.\n\nПосле успешной смены пароля происходит автоматический выход из системы. На email отправляется уведомление об изменении пароля.', uzFunctionality: 'Joriy va yangi parol uchun maydonlar bilan parolni o\'zgartirish formasini ochadi. Tizim joriy parolning mosligini va yangisining murakkabligini tekshiradi.\n\nYangi parol kiritilganda uning ishonchliligining indikatori ko\'rsatiladi. Tizim juda oddiy parollarni yoki oldingilariga mos keladigan parollarni ishlatishga yo\'l qo\'ymaydi.\n\nParol muvaffaqiyatli o\'zgartirilgandan so\'ng tizimdan avtomatik chiqish amalga oshiriladi. Emailga parol o\'zgartirish haqida bildirishnoma yuboriladi.' },

  { order: 198, ruDescription: 'Функция настройки уведомлений позволяет выбрать, о каких событиях система будет информировать пользователя. Это помогает быть в курсе важных изменений без постоянного мониторинга.\n\nМожно настроить уведомления по каналам: email, push-уведомления в браузере, Telegram. Для каждого типа события можно выбрать предпочтительный канал доставки.\n\nГибкая настройка уведомлений позволяет получать только релевантную информацию и не перегружать почту лишними сообщениями. Важно настроить уведомления под свои рабочие процессы.', uzDescription: 'Bildirishnomalarni sozlash funksiyasi foydalanuvchiga tizim qaysi hodisalar haqida xabar berishini tanlash imkonini beradi. Bu doimiy kuzatmasdan muhim o\'zgarishlardan xabardor bo\'lishga yordam beradi.\n\nKanallar bo\'yicha bildirishnomalarni sozlash mumkin: email, brauzerda push-bildirishnomalar, Telegram. Har bir hodisa turi uchun afzal ko\'rilgan yetkazish kanalini tanlash mumkin.\n\nBildirishnomalarning moslashuvchan sozlamalari faqat dolzarb ma\'lumotlarni olish va pochtani ortiqcha xabarlar bilan yuklamaslik imkonini beradi. Bildirishnomalarni o\'z ish jarayonlaringizga sozlash muhim.', ruFunctionality: 'Открывает панель настройки уведомлений с группировкой по типам событий. Можно включать и отключать уведомления для каждого типа, а также выбирать способ доставки.\n\nДоступные типы событий: продажи, возвраты, инкассация, низкие остатки, новые заказы, системные сообщения. Список зависит от роли пользователя и прав доступа.\n\nНастройки сохраняются мгновенно и применяются ко всем новым событиям. Можно включить режим "Не беспокоить" на определённое время.', uzFunctionality: 'Hodisa turlari bo\'yicha guruhlash bilan bildirishnomalarni sozlash panelini ochadi. Har bir tur uchun bildirishnomalarni yoqish va o\'chirish, shuningdek yetkazish usulini tanlash mumkin.\n\nMavjud hodisa turlari: sotuvlar, qaytarishlar, inkassatsiya, past qoldiqlar, yangi buyurtmalar, tizim xabarlar. Ro\'yxat foydalanuvchi roli va kirish huquqlariga bog\'liq.\n\nSozlamalar bir zumda saqlanadi va barcha yangi hodisalarga qo\'llaniladi. Muayyan vaqtga "Bezovta qilmang" rejimini yoqish mumkin.' },

  { order: 199, ruDescription: 'Раздел "История входов" показывает все авторизации пользователя в систему. Это важный инструмент для контроля безопасности аккаунта.\n\nВ истории отображается дата и время входа, IP-адрес, устройство и браузер. Можно быстро выявить подозрительные входы из незнакомых мест или устройств.\n\nПри обнаружении несанкционированного входа рекомендуется немедленно сменить пароль и проверить настройки безопасности. История помогает отслеживать, кто и когда использовал аккаунт.', uzDescription: '"Kirishlar tarixi" bo\'limi tizimga foydalanuvchining barcha avtorizatsiyalarini ko\'rsatadi. Bu akkaunt xavfsizligini nazorat qilish uchun muhim vosita.\n\nTarixda kirish sanasi va vaqti, IP-manzil, qurilma va brauzer ko\'rsatiladi. Noma\'lum joylardan yoki qurilmalardan shubhali kirishlarni tez aniqlash mumkin.\n\nRuxsatsiz kirish aniqlanganda darhol parolni o\'zgartirish va xavfsizlik sozlamalarini tekshirish tavsiya etiladi. Tarix akkauntdan kim va qachon foydalanganini kuzatishga yordam beradi.', ruFunctionality: 'Открывает список всех входов в аккаунт с детализацией по каждому. Показывается статус входа: успешный, неуспешный, с нового устройства.\n\nМожно завершить все активные сессии кроме текущей одной кнопкой. Это полезно при подозрении на компрометацию аккаунта.\n\nСистема автоматически отмечает подозрительные входы: из другой страны, с нового устройства, в неурочное время. На такие входы можно настроить дополнительные уведомления.', uzFunctionality: 'Har birini batafsil ko\'rish bilan akkauntga barcha kirishlar ro\'yxatini ochadi. Kirish holati ko\'rsatiladi: muvaffaqiyatli, muvaffaqiyatsiz, yangi qurilmadan.\n\nBir tugma bilan joriydan tashqari barcha faol sessiyalarni tugatish mumkin. Bu akkaunt oshkor qilingan shubha bo\'lganda foydali.\n\nTizim shubhali kirishlarni avtomatik belgilaydi: boshqa mamlakatdan, yangi qurilmadan, ish vaqtidan tashqarida. Bunday kirishlar uchun qo\'shimcha bildirishnomalarni sozlash mumkin.' },

  { order: 200, ruDescription: 'Функция удаления аккаунта позволяет пользователю полностью удалить свой аккаунт из системы. Это необратимое действие, требующее особой осторожности.\n\nПри удалении аккаунта все персональные данные пользователя стираются из системы. Документы и операции, созданные пользователем, сохраняются, но анонимизируются.\n\nПеред удалением система предупреждает о последствиях и требует подтверждения паролем. Рекомендуется выгрузить все нужные данные перед удалением аккаунта.', uzDescription: 'Akkauntni o\'chirish funksiyasi foydalanuvchiga o\'z akkauntini tizimdan to\'liq o\'chirish imkonini beradi. Bu maxsus ehtiyotkorlikni talab qiluvchi qaytarib bo\'lmaydigan harakat.\n\nAkkaunt o\'chirilganda foydalanuvchining barcha shaxsiy ma\'lumotlari tizimdan o\'chiriladi. Foydalanuvchi yaratgan hujjatlar va operatsiyalar saqlanadi, lekin anonimlashtiriladi.\n\nO\'chirishdan oldin tizim oqibatlari haqida ogohlantiradi va parol bilan tasdiqlashni talab qiladi. Akkauntni o\'chirishdan oldin barcha kerakli ma\'lumotlarni yuklab olish tavsiya etiladi.', ruFunctionality: 'Открывает форму удаления аккаунта с предупреждением о последствиях. Для подтверждения удаления необходимо ввести текущий пароль.\n\nСистема показывает список данных, которые будут удалены или анонимизированы. Это помогает пользователю принять осознанное решение.\n\nПосле подтверждения начинается процесс удаления, который может занять несколько минут. На email отправляется финальное уведомление об удалении аккаунта.', uzFunctionality: 'Oqibatlari haqida ogohlantirish bilan akkauntni o\'chirish formasini ochadi. O\'chirishni tasdiqlash uchun joriy parolni kiritish kerak.\n\nTizim o\'chiriladigan yoki anonimlashtiriladigan ma\'lumotlar ro\'yxatini ko\'rsatadi. Bu foydalanuvchiga ongli qaror qabul qilishga yordam beradi.\n\nTasdiqlangandan so\'ng o\'chirish jarayoni boshlanadi, bu bir necha daqiqa olishi mumkin. Emailga akkauntni o\'chirish haqida yakuniy bildirishnoma yuboriladi.' },
];

async function main() {
  console.log('Updating lessons 161-200 with detailed descriptions...');

  for (const lesson of detailedLessons) {
    await prisma.lesson.updateMany({
      where: { order: lesson.order },
      data: {
        ruDescription: lesson.ruDescription,
        uzDescription: lesson.uzDescription,
        ruFunctionality: lesson.ruFunctionality,
        uzFunctionality: lesson.uzFunctionality,
      },
    });
    console.log(`Updated lesson ${lesson.order}`);
  }

  console.log('Done! Updated 40 lessons (161-200)');
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
